import React, { useState, useEffect } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import styles from "./Menu.module.css";

const Menu = () => {
  const location = useLocation();
  const navigate = useNavigate();

  const [isOpen, setIsOpen] = useState(false);
  const [mode, setMode] = useState("login");
  const [user, setUser] = useState(null);

  const [isErrorOpen, setIsErrorOpen] = useState(false);
  const [errorMessage, setErrorMessage] = useState("");

  const [formData, setFormData] = useState({
    email: "",
    password: "",
    role: "organizer" // По умолчанию
  });

  const items = [
    { name: "Головна", path: "/" },
    { name: "Події", path: "/events" },
    { name: "Новини", path: "/news" },
    { name: "Про нас", path: "/about" }
  ];

  useEffect(() => {
    const storedUser = JSON.parse(localStorage.getItem("user"));
    if (storedUser) setUser(storedUser);
  }, []);

  const handleRegister = async () => {
    try {
      // При регистрации ВСЕГДА шлем роль organizer
      const res = await fetch("http://localhost:5000/auth/register", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          email: formData.email,
          password: formData.password,
          role: "organizer" 
        })
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Помилка реєстрації");

      alert("Реєстрація успішна! Тепер увійдіть.");
      setMode("login");
    } catch (err) {
      setErrorMessage(err.message);
      setIsErrorOpen(true);
    }
  };

  const handleLogin = async () => {
    try {
      const res = await fetch("http://localhost:5000/auth/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          email: formData.email,
          password: formData.password,
          role: formData.role // Здесь передаем выбранную в селекте роль
        })
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Невірний логін або пароль");

      localStorage.setItem("user", JSON.stringify(data.user));
      setUser(data.user);
      setIsOpen(false);

      if (data.user.role === "admin") {
        navigate("/admin");
      } else {
        navigate("/dashboard");
      }
    } catch (err) {
      setErrorMessage(err.message);
      setIsErrorOpen(true);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!formData.email || !formData.password) {
      setErrorMessage("Заповніть всі поля");
      setIsErrorOpen(true);
      return;
    }
    mode === "login" ? handleLogin() : handleRegister();
  };

  const logout = () => {
    localStorage.removeItem("user");
    setUser(null);
    navigate("/");
  };

  return (
    <>
      <nav className={styles.menu}>
        <div className={styles.menuInner}>
          <div className={styles.logo}>
            <Link to="/">SkillMeet</Link>
          </div>

          <ul>
            {items.map((item) => (
              <li key={item.name}>
                <Link
                  to={item.path}
                  className={location.pathname === item.path ? styles.active : ""}
                >
                  {item.name}
                </Link>
              </li>
            ))}
          </ul>

          {!user ? (
            <button className={styles.loginBtn} onClick={() => setIsOpen(true)}>
              Увійти
            </button>
          ) : (
            <div className={styles.userBlock}>
              <span className={styles.userEmail}>
                {user.email} <small>({user.role})</small>
              </span>
              <button className={styles.logoutBtn} onClick={logout}>
                Вийти
              </button>
            </div>
          )}
        </div>
      </nav>

      {/* МОДАЛКА ВХОДА/РЕГИСТРАЦИИ */}
      {isOpen && (
        <div className={styles.modalOverlay} onClick={() => setIsOpen(false)}>
          <div className={styles.modal} onClick={(e) => e.stopPropagation()}>
            <h2>{mode === "login" ? "Вхід" : "Реєстрація"}</h2>

            <form onSubmit={handleSubmit}>
              <input
                type="email"
                placeholder="Email"
                required
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
              />
              <input
                type="password"
                placeholder="Пароль"
                required
                value={formData.password}
                onChange={(e) => setFormData({ ...formData, password: e.target.value })}
              />

              {/* Селект выбора роли только при ВХОДЕ */}
              {mode === "login" && (
                <select
                  value={formData.role}
                  onChange={(e) => setFormData({ ...formData, role: e.target.value })}
                >
                  <option value="organizer">Я Організатор</option>
                  <option value="admin">Я Адміністратор</option>
                </select>
              )}

              <button type="submit" className={styles.submitBtn}>
                {mode === "login" ? "Увійти" : "Створити акаунт"}
              </button>
            </form>

            <p className={styles.switchMode}>
              {mode === "login" ? "Немає акаунта?" : "Вже є акаунт?"}
              <span onClick={() => setMode(mode === "login" ? "register" : "login")}>
                {mode === "login" ? "Реєстрація" : "Увійти"}
              </span>
            </p>

            <button className={styles.closeBtn} onClick={() => setIsOpen(false)}>
              Закрити
            </button>
          </div>
        </div>
      )}

      {/* ОШИБКА */}
      {isErrorOpen && (
        <div className={styles.modalOverlay} onClick={() => setIsErrorOpen(false)}>
          <div className={`${styles.modal} styles.errorModal`} onClick={(e) => e.stopPropagation()}>
            <h2>Помилка ❌</h2>
            <p>{errorMessage}</p>
            <button className={styles.closeBtn} onClick={() => setIsErrorOpen(false)}>
              Зрозуміло
            </button>
          </div>
        </div>
      )}
    </>
  );
};

export default Menu;
